$ErrorActionPreference="Stop";$root=Split-Path -Parent $PSScriptRoot;$godot=Get-ChildItem -LiteralPath (Join-Path $root ".tools\Godot") -Recurse -Filter "Godot*_mono_win64_console.exe"|Select-Object -First 1;if(-not $godot){throw "Portable Godot console executable was not found."};for($run=1;$run -le 10;$run++){$ErrorActionPreference="Continue";$output=& $godot.FullName --headless --fixed-fps 60 --path $root "res://scenes/Room24.tscn" --quit-after 1500 -- --room24-solution-smoke 2>&1;$exitCode=$LASTEXITCODE;$ErrorActionPreference="Stop";$output|Write-Output;if($exitCode -ne 0){throw "Room 24 solution smoke test run $run exited with code $exitCode"};if(($output-join"`n")-notmatch"ROOM24_SOLUTION_PASS: SolutionTrace shattered the entry barrier at (?!0\.00)([0-9]+\.[0-9]+) m/s, braked left to release the gate, crossed to the right accelerator lane and shattered the route barrier at (?!0\.00)([0-9]+\.[0-9]+) m/s"){throw "Room 24 run $run did not prove the split brittle-barrier route."}};Write-Output "ROOM24_SOLUTION_BATCH_PASS: 10 clean-process completions proved the gated split-break route."
